        local c_0xlll1Il, c_0xII1IIl = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0x1IllI1:sub(i_0xIIIlI1+2,i_0xIIIlI1+2)
        if ch3 == "=" then has3 = false else c_0xlll1Il = b64_0xIlIII1[ch3] or 0 end
        local ch4 = d_0x1IllI1:sub(i_0xIIIlI1+3,i_0xIIIlI1+3)
        if ch4 == "=" then has4 = false else c_0xII1IIl = b64_0xIlIII1[ch4] or 0 end
        local b_0xIlIIII = c_0xll1lll * (2^18) + c_0xIlIllI * (2^12) + c_0xlll1Il * (2^6) + c_0xII1IIl
        local b_0xlllIlI = math.floor(b_0xIlIIII / (2^16)) % (2^8)
        local b_0xIIlIl1 = math.floor(b_0xIlIIII / (2^8)) % (2^8)
        local b_0x1lIIIl = b_0xIlIIII % (2^8)
        table.insert(r_0x1Il1II, string.char(b_0xlllIlI))
        if has3 then table.insert(r_0x1Il1II, string.char(b_0xIIlIl1)) end
        if has4 then table.insert(r_0x1Il1II, string.char(b_0x1lIIIl)) end
