local function bxor_0xII1IIl(a_0xl11lII,b_0xlIIllI)
    if bit32 then return bit32.bxor(a_0xl11lII,b_0xlIIllI) end
    local r_0x1II1ll = 0
    for i_0xl1III1 = 0, 7 do
        local x_0xIlllll = a_0xl11lII % 2
        local y_0xIlllI1 = b_0xlIIllI % 2
        if x_0xIlllll ~= y_0xIlllI1 then r_0x1II1ll = r_0x1II1ll + (2^i_0xl1III1) end
        a_0xl11lII = math.floor(a_0xl11lII / 2)
        b_0xlIIllI = math.floor(b_0xlIIllI / 2)
    end
    return r_0x1II1ll
