        local kb_0xIllllI = string.byte(k_0xIIIIII, (i_0x1IlIll-1) % #k_0xIIIIII + 1)
        r_0xl11lII[i_0x1IlIll] = string.char(bxor_0xII1IIl(b_0xlIl1lI, kb_0xIllllI))
    end
    return table.concat(r_0xl11lII)
