local function getkeys_0xlIll1I()
    local seed = b64_0xIlIII1.dec_0xIIIIII("QlJRZzRpRmY=")
    local k1_enc = b64_0xIlIII1.dec_0xIIIIII("Mz0IKGwzKSk=")
    local k2_enc = b64_0xIlIII1.dec_0xIIIIII("EyI9HWAbLxQ=")
    return bxor_str_0xIlllII(k1_enc, seed), bxor_str_0xIlllII(k2_enc, seed)
